proof_block:
let idx = index as int;

// The synthetic det_set_mapping has
//     ensures (A_post1 && A_post2) ==> det_set_mapping_equal(...)
// where A_post1, A_post2 are `set_mapping`'s ensures applied to
// post1_self_ and post2_self_ respectively. NEITHER A_post1 NOR A_post2
// is a hypothesis at the top of the body — the previous sibling
// attempts (helper1/helper2/etc.) failed exactly because their
// top-level `assert(forall|i| ...)` over the per-run ensures was not
// derivable from `requires` alone.
//
// We materialize the antecedent by case-splitting on it with an `if`:
// inside the `if`-branch, every conjunct of the antecedent is in
// scope as a hypothesis, so we can do the standard trigger-pulling /
// case-split / Seq-extensionality dance. The post-merge effect is
// "antecedent ==> (page-array views are equal)", which is exactly the
// quantifier-instantiation hint z3 was missing.
if post1_self_.page_array.wf()
    && post2_self_.page_array.wf()
    && (forall|i: int|
        #![trigger post1_self_.page_array@[i]]
        #![trigger pre_self_.page_array@[i]]
        0 <= i < NUM_PAGES && i != index ==>
            post1_self_.page_array@[i] =~= pre_self_.page_array@[i])
    && (forall|i: int|
        #![trigger post2_self_.page_array@[i]]
        #![trigger pre_self_.page_array@[i]]
        0 <= i < NUM_PAGES && i != index ==>
            post2_self_.page_array@[i] =~= pre_self_.page_array@[i])
    && post1_self_.page_array@[idx].addr =~= pre_self_.page_array@[idx].addr
    && post1_self_.page_array@[idx].state =~= pre_self_.page_array@[idx].state
    && post1_self_.page_array@[idx].is_io_page =~= pre_self_.page_array@[idx].is_io_page
    && post1_self_.page_array@[idx].rev_pointer =~= pre_self_.page_array@[idx].rev_pointer
    && post1_self_.page_array@[idx].ref_count =~= pre_self_.page_array@[idx].ref_count
    && post1_self_.page_array@[idx].owning_container =~= pre_self_.page_array@[idx].owning_container
    && post1_self_.page_array@[idx].mappings =~= mapping
    && post1_self_.page_array@[idx].io_mappings =~= pre_self_.page_array@[idx].io_mappings
    && post2_self_.page_array@[idx].addr =~= pre_self_.page_array@[idx].addr
    && post2_self_.page_array@[idx].state =~= pre_self_.page_array@[idx].state
    && post2_self_.page_array@[idx].is_io_page =~= pre_self_.page_array@[idx].is_io_page
    && post2_self_.page_array@[idx].rev_pointer =~= pre_self_.page_array@[idx].rev_pointer
    && post2_self_.page_array@[idx].ref_count =~= pre_self_.page_array@[idx].ref_count
    && post2_self_.page_array@[idx].owning_container =~= pre_self_.page_array@[idx].owning_container
    && post2_self_.page_array@[idx].mappings =~= mapping
    && post2_self_.page_array@[idx].io_mappings =~= pre_self_.page_array@[idx].io_mappings
{
    // Pointwise Page equality. Case-split on the single touched index:
    //   * i == idx: each of the 8 Page fields is pinned (post1 and post2
    //     to the SAME value — pre_self_'s corresponding field, or the
    //     shared input `mapping`), so the two Pages agree field-wise and
    //     hence extensionally.
    //   * i != idx: mentioning `post1_self_.page_array@[i]` AND
    //     `post2_self_.page_array@[i]` in the goal fires both per-run
    //     `forall|i|` ensures through their (disjoint) triggers; both
    //     post-pages are forced to `pre_self_.page_array@[i]`.
    assert forall|i: int| 0 <= i < NUM_PAGES implies
        post1_self_.page_array@[i] =~= post2_self_.page_array@[i] by {
        if i == idx {
            assert(post1_self_.page_array@[i].addr =~= post2_self_.page_array@[i].addr);
            assert(post1_self_.page_array@[i].state =~= post2_self_.page_array@[i].state);
            assert(post1_self_.page_array@[i].is_io_page =~= post2_self_.page_array@[i].is_io_page);
            assert(post1_self_.page_array@[i].rev_pointer =~= post2_self_.page_array@[i].rev_pointer);
            assert(post1_self_.page_array@[i].ref_count =~= post2_self_.page_array@[i].ref_count);
            assert(post1_self_.page_array@[i].owning_container =~= post2_self_.page_array@[i].owning_container);
            assert(post1_self_.page_array@[i].mappings =~= post2_self_.page_array@[i].mappings);
            assert(post1_self_.page_array@[i].io_mappings =~= post2_self_.page_array@[i].io_mappings);
        } else {
            assert(post1_self_.page_array@[i] =~= pre_self_.page_array@[i]);
            assert(post2_self_.page_array@[i] =~= pre_self_.page_array@[i]);
        }
    }

    // Lift the pointwise Page equality to view-level Seq equality of
    // the underlying page_array view (= `seq@` on the Array struct).
    assert(post1_self_.page_array@ =~= post2_self_.page_array@);
}
